import React, { useState, useEffect } from 'react';

const OIDCClient = () => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const config = {
    clientId: 'your-client-id',
    redirectUri: 'http://localhost:3000/callback',
    authorizationEndpoint: 'https://your-oidc-provider.com/oauth2/authorize',
    tokenEndpoint: 'https://your-oidc-provider.com/oauth2/token',
    logoutEndpoint: 'https://your-oidc-provider.com/oauth2/logout'
  };

  // Generate secure random state parameter
  const generateState = () => {
    const array = new Uint8Array(32);
    crypto.getRandomValues(array);
    return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
  };

  // Store state in sessionStorage
  const storeState = (state) => {
    sessionStorage.setItem('oidc_state', state);
  };

  // Retrieve and validate state
  const validateState = (receivedState) => {
    const storedState = sessionStorage.getItem('oidc_state');
    if (!storedState || storedState !== receivedState) {
      throw new Error('Invalid state parameter');
    }
    sessionStorage.removeItem('oidc_state');
    return true;
  };

  // Decode JWT token
  const decodeToken = (token) => {
    try {
      const base64Url = token.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(atob(base64).split('').map(c => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2)).join(''));
      return JSON.parse(jsonPayload);
    } catch (error) {
      console.error('Error decoding token:', error);
      return null;
    }
  };

  // Handle login redirect
  const handleLogin = () => {
    const state = generateState();
    storeState(state);
    
    const params = new URLSearchParams({
      response_type: 'code',
      client_id: config.clientId,
      redirect_uri: config.redirectUri,
      scope: 'openid profile email',
      state: state,
      nonce: Date.now().toString()
    });

    window.location.href = `${config.authorizationEndpoint}?${params.toString()}`;
  };

  // Handle logout
  const handleLogout = () => {
    const logoutParams = new URLSearchParams({
      post_logout_redirect_uri: config.redirectUri,
      client_id: config.clientId
    });
    
    setUser(null);
    window.location.href = `${config.logoutEndpoint}?${logoutParams.toString()}`;
  };

  // Handle callback
  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');

    if (code && state) {
      try {
        validateState(state);
        exchangeCodeForToken(code);
      } catch (err) {
        setError(err.message);
        console.error('Authentication error:', err);
      }
    } else if (urlParams.get('error')) {
      setError(urlParams.get('error_description') || 'Authentication failed');
    }
  }, []);

  // Exchange authorization code for tokens
  const exchangeCodeForToken = async (code) => {
    setLoading(true);
    setError(null);

    try {
      const response = await fetch(config.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': 'Basic ' + btoa(`${config.clientId}:${config.clientSecret}`)
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: config.redirectUri
        })
      });

      if (!response.ok) {
        throw new Error(`Token exchange failed: ${response.status}`);
      }

      const tokens = await response.json();
      const decodedIdToken = decodeToken(tokens.id_token);
      
      if (decodedIdToken) {
        setUser({
          ...decodedIdToken,
          accessToken: tokens.access_token,
          refreshToken: tokens.refresh_token
        });
      }
    } catch (err) {
      setError(err.message);
      console.error('Token exchange error:', err);
    } finally {
      setLoading(false);
    }
  };

  // Refresh access token
  const refreshAccessToken = async (refreshToken) => {
    try {
      const response = await fetch(config.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': 'Basic ' + btoa(`${config.clientId}:${config.clientSecret}`)
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          refresh_token: refreshToken
        })
      });

      if (!response.ok) {
        throw new Error('Token refresh failed');
      }

      const tokens = await response.json();
      const decodedIdToken = decodeToken(tokens.id_token);
      
      if (decodedIdToken) {
        setUser(prev => ({
          ...prev,
          ...decodedIdToken,
          accessToken: tokens.access_token,
          refreshToken: tokens.refresh_token
        }));
      }
    } catch (err) {
      console.error('Token refresh error:', err);
      handleLogout();
    }
  };

  return (
    <div>
      {error && <div style={{color: 'red'}}>Error: {error}</div>}
      {loading && <div>Loading...</div>}
      
      {!user ? (
        <button onClick={handleLogin} disabled={loading}>
          Login
        </button>
      ) : (
        <div>
          <p>Welcome, {user.name || user.email}</p>
          <button onClick={handleLogout}>Logout</button>
        </div>
      )}
    </div>
  );
};

export default OIDCClient;